    dist.assign(n, 100000); // Initialize all distances as 'infinite'
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    dist[src] = 0; // Distance from src to src is 0
    pq.push({0, src});

    while (!pq.empty()) {
        int distance = pq.top().first;
        int node = pq.top().second;
        pq.pop();

        // Avoid exploring paths that are already longer than the known shortest path
        if (distance > dist[node])
            continue;

        for (auto it : adj[node]) {
            int next_n = it.first;
            int next_d = it.second;

            if (distance + next_d < dist[next_n]) {
                dist[next_n] = distance + next_d;
                pq.push({dist[next_n], next_n});
            }
        }
    }
}

